    {
        if (Directory.Exists(_tempRoot))
            Directory.Delete(_tempRoot, true);
    }

    #region Nbt helpers

    private static void WriteLevelDat(string folderPath, Action<fNbt.NbtCompound> populateData)
    {
        var root = new fNbt.NbtCompound("");
        var data = new fNbt.NbtCompound("Data");
        populateData(data);
        root.Add(data);

        var nbtFile = new fNbt.NbtFile(root);
        var path = Path.Combine(folderPath, "level.dat");
        using var fs = new FileStream(path, FileMode.Create, FileAccess.Write, FileShare.None);
        nbtFile.SaveToStream(fs, fNbt.NbtCompression.GZip);
    }

