    [TestMethod]
    public async Task LoadSaveAsync_PreLegacySave_ReturnsCorrectInfo()
    {
        var folder = Path.Combine(_tempRoot, "PreLegacyWorld");
        Directory.CreateDirectory(folder);
        WriteLevelDat(folder, data =>
        {
            data.Add(new fNbt.NbtString("LevelName", "OldWorld"));
            data.Add(new fNbt.NbtLong("RandomSeed", 123456789L));
            data.Add(new fNbt.NbtLong("LastPlayed", 0));
            data.Add(new fNbt.NbtLong("Time", 2400L)); // 2 min
            data.Add(new fNbt.NbtInt("GameType", 0));
            data.Add(new fNbt.NbtInt("SpawnX", 100));
            data.Add(new fNbt.NbtInt("SpawnY", 64));
            data.Add(new fNbt.NbtInt("SpawnZ", 200));
        });

        var info = await _saveManager.LoadSaveAsync(folder);

        Assert.AreEqual("OldWorld", info.LevelName);
        Assert.AreEqual(123456789L, info.Seed);
        Assert.AreEqual(GameMode.Survival, info.GameMode);
        Assert.IsNull(info.Difficulty);
        Assert.IsFalse(info.AllowCommands);
        Assert.IsNotNull(info.Spawn);
        Assert.AreEqual(100f, info.Spawn!.Value.X);
        Assert.AreEqual(64f, info.Spawn!.Value.Y);
        Assert.AreEqual(200f, info.Spawn!.Value.Z);
    }

